Title: FastAPI SQLAlchemy CRUD with SQLite

Category: FastAPI Project Examples

Description: A Docker based FastAPI project that combines Pydantic schemas, SQLAlchemy models, SQLite, CRUD routes, and user-post relationships.

Intro: This setup creates a complete small FastAPI backend slice. It uses Pydantic schemas for request and response contracts, SQLAlchemy models for database tables, SQLite for local persistence, and CRUD routes for users and posts.

Section: Create the FastAPI app

Create the main application file at app/main.py. This file creates the database tables on startup and defines the user and post CRUD routes.

Code (text):
app/main.py

Code (python):
from contextlib import asynccontextmanager

from fastapi import Depends, FastAPI, HTTPException, Response, status
from sqlalchemy import or_, select
from sqlalchemy.orm import Session, selectinload

from app import models
from app.database import Base, engine, get_db
from app.schemas import (
 PostCreate,
 PostResponse,
 PostUpdate,
 UserCreate,
 UserResponse,
 UserUpdate,
 UserWithPosts,
)

@asynccontextmanager
async def lifespan(_app):
 Base.metadata.create_all(bind=engine)
 yield

app = FastAPI(
 title="02 SQLAlchemy CRUD",
 lifespan=lifespan,
)

@app.get("/")
def home():
 return {
 "message": "FastAPI SQLAlchemy CRUD example"
 }

@app.post(
 "/users",
 response_model=UserResponse,
 status_code=status.HTTP_201_CREATED,
)
def create_user(
 user: UserCreate,
 db: Session = Depends(get_db),
):
 existing_user = db.execute(
 select(models.User).where(
 or_(
 models.User.username == user.username,
 models.User.email == user.email,
 )
 )
 ).scalar_one_or_none()

 if existing_user:
 raise HTTPException(
 status_code=status.HTTP_409_CONFLICT,
 detail="Username or email already exists",
 )

 db_user = models.User(
 username=user.username,
 email=user.email,
 )

 db.add(db_user)
 db.commit()
 db.refresh(db_user)

 return db_user

@app.get("/users", response_model=list[UserResponse])
def list_users(db: Session = Depends(get_db)):
 users = db.execute(
 select(models.User).order_by(models.User.id)
 ).scalars().all()

 return users

@app.get("/users/{user_id}", response_model=UserWithPosts)
def get_user(
 user_id: int,
 db: Session = Depends(get_db),
):
 user = db.execute(
 select(models.User)
 .options(selectinload(models.User.posts))
 .where(models.User.id == user_id)
 ).scalar_one_or_none()

 if not user:
 raise HTTPException(
 status_code=status.HTTP_404_NOT_FOUND,
 detail="User not found",
 )

 return user

@app.patch("/users/{user_id}", response_model=UserResponse)
def update_user(
 user_id: int,
 payload: UserUpdate,
 db: Session = Depends(get_db),
):
 user = db.get(models.User, user_id)

 if not user:
 raise HTTPException(
 status_code=status.HTTP_404_NOT_FOUND,
 detail="User not found",
 )

 update_data = payload.model_dump(exclude_unset=True)

 for field, value in update_data.items():
 setattr(user, field, value)

 db.commit()
 db.refresh(user)

 return user

@app.delete("/users/{user_id}", status_code=status.HTTP_204_NO_CONTENT)
def delete_user(
 user_id: int,
 db: Session = Depends(get_db),
):
 user = db.get(models.User, user_id)

 if not user:
 raise HTTPException(
 status_code=status.HTTP_404_NOT_FOUND,
 detail="User not found",
 )

 db.delete(user)
 db.commit()

 return Response(status_code=status.HTTP_204_NO_CONTENT)

@app.post(
 "/users/{user_id}/posts",
 response_model=PostResponse,
 status_code=status.HTTP_201_CREATED,
)
def create_post(
 user_id: int,
 post: PostCreate,
 db: Session = Depends(get_db),
):
 user = db.get(models.User, user_id)

 if not user:
 raise HTTPException(
 status_code=status.HTTP_404_NOT_FOUND,
 detail="User not found",
 )

 db_post = models.Post(
 title=post.title,
 content=post.content,
 user_id=user.id,
 )

 db.add(db_post)
 db.commit()
 db.refresh(db_post)

 return db_post

@app.get("/posts", response_model=list[PostResponse])
def list_posts(db: Session = Depends(get_db)):
 posts = db.execute(
 select(models.Post).order_by(models.Post.id)
 ).scalars().all()

 return posts

@app.get("/posts/{post_id}", response_model=PostResponse)
def get_post(
 post_id: int,
 db: Session = Depends(get_db),
):
 post = db.get(models.Post, post_id)

 if not post:
 raise HTTPException(
 status_code=status.HTTP_404_NOT_FOUND,
 detail="Post not found",
 )

 return post

@app.patch("/posts/{post_id}", response_model=PostResponse)
def update_post(
 post_id: int,
 payload: PostUpdate,
 db: Session = Depends(get_db),
):
 post = db.get(models.Post, post_id)

 if not post:
 raise HTTPException(
 status_code=status.HTTP_404_NOT_FOUND,
 detail="Post not found",
 )

 update_data = payload.model_dump(exclude_unset=True)

 for field, value in update_data.items():
 setattr(post, field, value)

 db.commit()
 db.refresh(post)

 return post

@app.delete("/posts/{post_id}", status_code=status.HTTP_204_NO_CONTENT)
def delete_post(
 post_id: int,
 db: Session = Depends(get_db),
):
 post = db.get(models.Post, post_id)

 if not post:
 raise HTTPException(
 status_code=status.HTTP_404_NOT_FOUND,
 detail="Post not found",
 )

 db.delete(post)
 db.commit()

 return Response(status_code=status.HTTP_204_NO_CONTENT)

