 select(models.Post).order_by(models.Post.id)
 ).scalars().all()

 return posts

@app.patch("/posts/{post_id}", response_model=PostResponse)
def update_post(
 post_id: int,
 payload: PostUpdate,
 current_user: Annotated[models.User, Depends(get_current_user)],
 db: Annotated[Session, Depends(get_db)],
):
