Title: FastAPI Alembic Migrations with Docker

Category: FastAPI Project Examples

Description: A Docker based FastAPI project that uses SQLAlchemy models, PostgreSQL, and Alembic migrations instead of creating tables directly at startup.

Intro: This setup shows the production style database workflow for FastAPI projects. SQLAlchemy models define the table structure, Alembic generates migration files, and Docker Compose runs both the FastAPI backend and PostgreSQL database.

Section: Create the FastAPI app

Create the main application file at app/main.py. The app does not create tables on startup. Database schema changes are handled by Alembic commands.

Code (text):
app/main.py

Code (python):
from fastapi import Depends, FastAPI, HTTPException, status
from sqlalchemy import or_, select
from sqlalchemy.orm import Session

from app import models
from app.database import get_db
from app.schemas import PostCreate, PostResponse, UserCreate, UserResponse

app = FastAPI(title="06 Alembic Migrations")

@app.get("/")
def home():
 return {
 "message": "FastAPI Alembic migration example"
 }

@app.post(
 "/users",
 response_model=UserResponse,
 status_code=status.HTTP_201_CREATED,
)
def create_user(
 payload: UserCreate,
 db: Session = Depends(get_db),
):
 existing_user = db.execute(
 select(models.User).where(
 or_(
 models.User.username == payload.username,
 models.User.email == payload.email,
 )
 )
 ).scalar_one_or_none()

 if existing_user:
 raise HTTPException(
 status_code=status.HTTP_409_CONFLICT,
 detail="Username or email already exists",
 )

 user = models.User(
 username=payload.username,
 email=payload.email,
 )

 db.add(user)
 db.commit()
 db.refresh(user)

 return user

@app.get("/users", response_model=list[UserResponse])
def list_users(db: Session = Depends(get_db)):
 users = db.execute(
 select(models.User).order_by(models.User.id)
 ).scalars().all()

 return users

@app.post(
 "/users/{user_id}/posts",
 response_model=PostResponse,
 status_code=status.HTTP_201_CREATED,
)
def create_post(
 user_id: int,
 payload: PostCreate,
 db: Session = Depends(get_db),
):
 user = db.get(models.User, user_id)

 if not user:
 raise HTTPException(
 status_code=status.HTTP_404_NOT_FOUND,
 detail="User not found",
 )

 post = models.Post(
 title=payload.title,
 content=payload.content,
 user_id=user.id,
 )

 db.add(post)
 db.commit()
 db.refresh(post)

 return post

@app.get("/posts", response_model=list[PostResponse])
def list_posts(db: Session = Depends(get_db)):
 posts = db.execute(
 select(models.Post).order_by(models.Post.id)
 ).scalars().all()

 return posts

