Title: FastAPI Error Handling and API Responses

Category: FastAPI Project Examples

Description: A Docker based FastAPI project that uses custom exceptions, global exception handlers, validation error shaping, and consistent API response contracts.

Intro: This setup creates a focused FastAPI error handling project. It separates success responses from error responses, uses custom exception classes for domain errors, handles validation errors consistently, and returns predictable JSON shapes for client applications.

Section: Create the FastAPI app

Create the main application file at app/main.py. This file registers the exception handlers and defines routes that raise domain errors when something fails.

Code (text):
app/main.py

Code (python):
from fastapi import FastAPI, HTTPException, Response, status
from fastapi.exceptions import RequestValidationError
from starlette.exceptions import HTTPException as StarletteHTTPException

from app import store
from app.exceptions import (
 AppError,
 ForbiddenActionError,
 InvalidOperationError,
 UserAlreadyExistsError,
 UserNotFoundError,
)
from app.handlers import (
 app_error_handler,
 http_error_handler,
 unhandled_error_handler,
 validation_error_handler,
)
from app.schemas import ErrorResponse, SuccessResponse, UserCreate, UserResponse, UserUpdate

app = FastAPI(title="08 Error Handling Responses")

app.add_exception_handler(AppError, app_error_handler)
app.add_exception_handler(StarletteHTTPException, http_error_handler)
app.add_exception_handler(RequestValidationError, validation_error_handler)
app.add_exception_handler(Exception, unhandled_error_handler)

@app.get("/")
def home():
 return {
 "message": "FastAPI error handling example"
 }

@app.post(
 "/users",
 response_model=UserResponse,
 status_code=status.HTTP_201_CREATED,
 responses={
 409: {
 "model": ErrorResponse
 },
 422: {
 "model": ErrorResponse
 },
 },
)
def create_user(payload: UserCreate):
 if store.username_or_email_exists(payload.username, payload.email):
 raise UserAlreadyExistsError()

 return store.create_user(payload)

@app.get("/users", response_model=list[UserResponse])
def list_users():
 return store.list_users()

@app.get(
 "/users/{user_id}",
 response_model=UserResponse,
 responses={
 404: {
 "model": ErrorResponse
 },
 },
)
def get_user(user_id: int):
 user = store.get_user(user_id)

 if not user:
 raise UserNotFoundError()

 return user

@app.patch(
 "/users/{user_id}",
 response_model=UserResponse,
 responses={
 400: {
 "model": ErrorResponse
 },
 404: {
 "model": ErrorResponse
 },
 422: {
 "model": ErrorResponse
 },
 },
)
def update_user(user_id: int, payload: UserUpdate):
 update_data = payload.model_dump(exclude_unset=True)

 if not update_data:
 raise InvalidOperationError(
 message="At least one field must be provided",
 )

 user = store.update_user(user_id, update_data)

 if not user:
 raise UserNotFoundError()

 return user

@app.delete(
 "/users/{user_id}",
 status_code=status.HTTP_204_NO_CONTENT,
 responses={
 403: {
 "model": ErrorResponse
 },
 404: {
 "model": ErrorResponse
 },
 },
)
def delete_user(user_id: int):
 if user_id == 1:
 raise ForbiddenActionError(
 message="The first user cannot be deleted in this example",
 )

 user = store.delete_user(user_id)

 if not user:
 raise UserNotFoundError()

 return Response(status_code=status.HTTP_204_NO_CONTENT)

@app.get(
 "/manual-http-error",
 responses={
 418: {
 "model": ErrorResponse
 },
 },
)
def manual_http_error():
 raise HTTPException(
 status_code=418,
 detail="Manual HTTP exception example",
 )

@app.get(
 "/crash",
 responses={
 500: {
 "model": ErrorResponse
 },
 },
)
def crash():
 raise RuntimeError("Simulated unexpected crash")

The responses argument improves the generated OpenAPI documentation by showing which error response model can be returned from each route.

